// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract DocumentRegistry {
    address public owner;
    address public newOwnerCandidate;
    mapping(uint256 => bytes32) private documentHashes;
    mapping(uint256 => uint256) private lastCalledTime;
    mapping(uint256 => uint256) private callCount;

    uint256 public constant RATE_LIMIT_PERIOD = 1 minutes; // Define rate limit period
    uint256 public constant MAX_CALLS_PER_PERIOD = 5; // Define max calls per period

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event DocumentRegistered(uint256 indexed docId, bytes32 hash);
    error RateLimitExceeded();
    error InvalidAddress();
    error NotTheOwner();
    error DocumentAlreadyRegistered();

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only the contract owner can call this function");
        _;
    }

    function proposeNewOwner(address _newOwner) external onlyOwner {
        require(_newOwner != address(0), "Invalid address");
        newOwnerCandidate = _newOwner;
    }

    function acceptOwnership() external {
        require(msg.sender == newOwnerCandidate, "Not the proposed new owner");
        emit OwnershipTransferred(owner, newOwnerCandidate);
        owner = newOwnerCandidate;
        newOwnerCandidate = address(0);
    }

    function cancelOwnershipTransfer() external onlyOwner {
        newOwnerCandidate = address(0);
    }

    function registerDocument(uint256 docId, string memory hash) public onlyOwner {
        require(documentHashes[docId] == 0, "Document already registered");
        documentHashes[docId] = keccak256(abi.encodePacked(hash));
        emit DocumentRegistered(docId, documentHashes[docId]);
    }

    modifier rateLimited(uint256 docId) {
        uint256 currentBlockTimestamp = block.timestamp;
        if (currentBlockTimestamp <= lastCalledTime[docId]) {
            require(callCount[docId] < MAX_CALLS_PER_PERIOD, "Rate limit exceeded");
        } else {
            callCount[docId] = 0;
            lastCalledTime[docId] = currentBlockTimestamp + RATE_LIMIT_PERIOD;
        }
        callCount[docId]++;
        _;
    }

    function getDocumentHash(uint256 docId) public view rateLimited(docId) returns (bytes32) {
        require(documentHashes[docId] != 0, "Document does not exist");
        return documentHashes[docId];
    }

    function documentExists(uint256 docId) public view returns (bool) {
        return documentHashes[docId] != 0;
    }
}
